     1→use axum::Router;
     2→use sqlx::postgres::PgPoolOptions;
     3→use sqlx::PgPool;
     4→use tokio::net::TcpListener;
     5→
     6→use crate::configuration::Settings;
     7→use crate::routes::health_check;
     8→
     9→pub struct Application {
    10→    listener: TcpListener,
    11→    pool: PgPool,
    12→}
    13→
    14→impl Application {
    15→    pub async fn build(settings: &Settings) -> Result<Self, anyhow::Error> {
    16→        let pool = PgPoolOptions::new()
    17→            .max_connections(5)
    18→            .connect_with(settings.database.connect_options())
    19→            .await?;
    20→
    21→        let address = format!(
    22→            "{}:{}",
    23→            settings.application.host, settings.application.port
    24→        );
    25→        let listener = TcpListener::bind(&address).await?;
    26→
    27→        tracing::info!("Listening on {}", listener.local_addr()?);
    28→
    29→        Ok(Self { listener, pool })
    30→    }
    31→
    32→    pub fn port(&self) -> u16 {
    33→        self.listener.local_addr().unwrap().port()
    34→    }
    35→
    36→    pub fn router(pool: PgPool) -> Router {
